const MASTER_BANK_BY_ID = new Map(
  TRANSFER_PLANNER_MASTER_BANK_LIBRARY.map((bank) => [bank.id, bank] as const)
);

const MASTER_CHAIN_BY_ID = new Map(
  TRANSFER_PLANNER_MASTER_CHAIN_LIBRARY.map((chain) => [chain.id, chain] as const)
);

function normalizePlannerLookupValue(value: string) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/\([^)]*\)/g, " ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizePlannerLookupKeyValue(value: string) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function buildPlannerLookupKey(campusId: TransferPlannerCampusId, title: string) {
  return `${campusId}:${normalizePlannerLookupKeyValue(title)}`;
}

function buildPlannerMergeKey(campusId: TransferPlannerCampusId, title: string) {
  return `${campusId}:${normalizePlannerLookupValue(title)}`;
}

function buildPlannerPlanId(campusId: TransferPlannerCampusId, title: string) {
  return `${campusId}-${normalizePlannerLookupValue(title).replace(/\s+/g, "-")}`;
}

function buildShortPlannerTitle(title: string) {
  return String(title ?? "")
    .replace(/\s+\([^)]*\)/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

const MASTER_MAJOR_ROW_BY_EXACT_KEY = new Map(
  TRANSFER_PLANNER_MASTER_MAJOR_ROWS.map((row) => [
    buildPlannerLookupKey(row.campusId, row.title),
    row,
  ] as const)
);

const MASTER_MAJOR_ROW_BY_KEY = new Map(
  TRANSFER_PLANNER_MASTER_MAJOR_ROWS.map((row) => [
    buildPlannerMergeKey(row.campusId, row.title),
    row,
  ] as const)
);

function getMasterRowForPlan(plan: TransferPlannerMajorPlan) {
  const aliasedTitle = TRANSFER_PLANNER_MASTER_TITLE_ALIASES[plan.id] ?? plan.title;
  return (
    MASTER_MAJOR_ROW_BY_EXACT_KEY.get(buildPlannerLookupKey(plan.campusId, aliasedTitle)) ??
    MASTER_MAJOR_ROW_BY_EXACT_KEY.get(buildPlannerLookupKey(plan.campusId, plan.title)) ??
    MASTER_MAJOR_ROW_BY_EXACT_KEY.get(buildPlannerLookupKey(plan.campusId, plan.shortTitle)) ??
    MASTER_MAJOR_ROW_BY_KEY.get(buildPlannerMergeKey(plan.campusId, aliasedTitle)) ??
    MASTER_MAJOR_ROW_BY_KEY.get(buildPlannerMergeKey(plan.campusId, plan.shortTitle)) ??
    null
  );
}

function getMergedReferenceIds(existingIds: string[] | undefined, masterIds: string[]) {
  return Array.from(new Set([...(existingIds ?? []), ...masterIds]));
}

function normalizeReferenceCourseLabel(value: string) {
  return String(value ?? "").replace(/\s+/g, " ").trim();
}

function uniqueReferenceCourseLabels(items: string[]) {
  const seen = new Set<string>();
  const uniqueItems: string[] = [];

  for (const item of items) {
    const normalized = normalizeReferenceCourseLabel(item);
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    uniqueItems.push(normalized);
  }

  return uniqueItems;
}

function uniquePlannerStrings(items: string[]) {
  const seen = new Set<string>();
  const uniqueItems: string[] = [];

  for (const item of items) {
    const normalized = String(item ?? "").trim();
    if (!normalized || seen.has(normalized)) continue;
    seen.add(normalized);
    uniqueItems.push(normalized);
  }

  return uniqueItems;
}

function uniquePlannerLinks(items: TransferPlannerLink[]) {
  const seen = new Set<string>();
  const uniqueItems: TransferPlannerLink[] = [];

  for (const item of items) {
    const key = String(item?.url ?? "").trim() || `${item.label}|${item.note ?? ""}`;
    if (!key || seen.has(key)) continue;
    seen.add(key);
    uniqueItems.push(item);
  }

  return uniqueItems;
}

function getChecklistReferenceCoursesFromItems(items: TransferPlannerChecklistItem[]) {
  return uniqueReferenceCourseLabels(
    items.flatMap((item) => [item.grcCourses, ...(item.alternatives ?? [])].flat())
  );
}

function getChecklistReferenceCourses(plan: TransferPlannerMajorPlan) {
  return getChecklistReferenceCoursesFromItems([
    ...plan.applicationChecklist,
    ...plan.beforeEnrollmentChecklist,
    ...plan.stayAtGrcChecklist,
  ]);
}

function materializePlannerPathway(pathway: TransferPlannerMajorPathway): TransferPlannerMajorPathway {
  return {
    ...pathway,
    grcCourseList: uniqueReferenceCourseLabels([
      ...(pathway.grcCourseList ?? []),
      ...getChecklistReferenceCoursesFromItems([
        ...(pathway.applicationChecklist ?? []),
        ...(pathway.beforeEnrollmentChecklist ?? []),
        ...(pathway.stayAtGrcChecklist ?? []),
      ]),
    ]),
    advisorFlags: uniquePlannerStrings(pathway.advisorFlags ?? []),
    officialLinks: uniquePlannerLinks(pathway.officialLinks ?? []),
    manualReviewNotes: uniquePlannerStrings(pathway.manualReviewNotes ?? []),
    grcCourseListGuidance: String(pathway.grcCourseListGuidance ?? "").trim() || undefined,
    whyThisTrack: uniquePlannerStrings(pathway.whyThisTrack ?? []),
  };
}

function materializePlanPathways(plan: TransferPlannerMajorPlan) {
  return (plan.pathways ?? []).map(materializePlannerPathway);
}

function mergePlannerPathwayWithPlan(
  plan: TransferPlannerMajorPlan,
  pathway: TransferPlannerMajorPathway
): TransferPlannerResolvedMajorPlan {
  const mergedPlan = materializePlanReferenceCourses({
    ...plan,
    applicationChecklist: pathway.applicationChecklist ?? plan.applicationChecklist,
    beforeEnrollmentChecklist:
      pathway.beforeEnrollmentChecklist ?? plan.beforeEnrollmentChecklist,
    stayAtGrcChecklist: pathway.stayAtGrcChecklist ?? plan.stayAtGrcChecklist,
    advisorFlags: uniquePlannerStrings([...(plan.advisorFlags ?? []), ...(pathway.advisorFlags ?? [])]),
    officialLinks: uniquePlannerLinks([...(plan.officialLinks ?? []), ...(pathway.officialLinks ?? [])]),
    degreeMapSections: pathway.degreeMapSections ?? plan.degreeMapSections,
    manualReviewNotes: uniquePlannerStrings([
      ...(plan.manualReviewNotes ?? []),
      ...(pathway.manualReviewNotes ?? []),
    ]),
    grcCourseListGuidance:
      pathway.grcCourseListGuidance ?? plan.grcCourseListGuidance,
    grcCourseList:
      pathway.grcCourseList && pathway.grcCourseList.length
        ? pathway.grcCourseList
        : plan.grcCourseList,
    plannerNote: pathway.plannerNote ?? plan.plannerNote,
    bestTrackId:
      pathway.bestTrackId === undefined ? plan.bestTrackId : pathway.bestTrackId,
    bestTrackSummary: pathway.bestTrackSummary ?? plan.bestTrackSummary,
    whyThisTrack: pathway.whyThisTrack?.length
      ? pathway.whyThisTrack
      : plan.whyThisTrack,
    financialAidNote: pathway.financialAidNote ?? plan.financialAidNote,
  });

  return {
    ...mergedPlan,
    pathways: materializePlanPathways(plan),
    selectedPathwayId: pathway.id,
    selectedPathwayLabel: pathway.label,
    selectedPathwaySummary: pathway.summary,
  };
}

export function getTransferPlannerPathwaysForPlan(
  plan: TransferPlannerMajorPlan | null | undefined
) {
  if (!plan?.pathways?.length) return [] as TransferPlannerMajorPathway[];
  return materializePlanPathways(plan);
}

export function resolveTransferPlannerMajorPlan(
  plan: TransferPlannerMajorPlan | null | undefined,
  pathwayId: string | null | undefined
) {
  if (!plan) return null as TransferPlannerResolvedMajorPlan | null;

  const pathways = materializePlanPathways(plan);
  if (!pathways.length) {
    return {
      ...materializePlanReferenceCourses(plan),
      pathways: [],
      selectedPathwayId: null,
      selectedPathwayLabel: null,
      selectedPathwaySummary: null,
    };
  }

  const selectedPathway =
    pathways.find((entry) => entry.id === pathwayId) ?? pathways[0] ?? null;

  if (!selectedPathway) {
    return {
      ...materializePlanReferenceCourses(plan),
      pathways,
      selectedPathwayId: null,
      selectedPathwayLabel: null,
      selectedPathwaySummary: null,
    };
  }

  return mergePlannerPathwayWithPlan(plan, selectedPathway);
}

function getResolvedChecklistReferenceCourses(plan: TransferPlannerResolvedMajorPlan) {
  return uniqueReferenceCourseLabels(
    [
      ...plan.applicationChecklist,
      ...plan.beforeEnrollmentChecklist,
      ...plan.stayAtGrcChecklist,
    ].flatMap((item) => [item.grcCourses, ...(item.alternatives ?? [])].flat())
  );
}

function getBankReferenceCourses(bankIds: string[] | undefined) {
  return uniqueReferenceCourseLabels(
    (bankIds ?? []).flatMap((bankId) => MASTER_BANK_BY_ID.get(bankId)?.courses ?? [])
  );
}

function materializePlanReferenceCourses(plan: TransferPlannerMajorPlan): TransferPlannerMajorPlan {
  return {
    ...plan,
    pathways: materializePlanPathways(plan),
    grcCourseList: uniqueReferenceCourseLabels([
      ...(plan.grcCourseList ?? []),
      ...getChecklistReferenceCourses(plan),
      ...getBankReferenceCourses(plan.bankIds),
    ]),
  };
}

function mergeDetailedPlanWithMaster(plan: TransferPlannerMajorPlan): TransferPlannerMajorPlan {
  const masterRow = getMasterRowForPlan(plan);
  const override = GENERATED_PLAN_DOC_OVERRIDES[
    buildPlannerLookupKey(plan.campusId, masterRow?.title ?? plan.title)
  ];
  const mergedManualReviewNotes = uniquePlannerStrings([
    ...(plan.manualReviewNotes ?? []),
    ...(override?.manualReviewNotes ?? []),
  ]);

  if (!masterRow) {
    return materializePlanReferenceCourses({
      ...plan,
      officialLinks: uniquePlannerLinks([
        ...(plan.officialLinks ?? []),
        ...(override?.officialLinks ?? []),
      ]),
      degreeMapSections:
        plan.degreeMapSections?.length ? plan.degreeMapSections : override?.degreeMapSections,
      manualReviewNotes: mergedManualReviewNotes.length ? mergedManualReviewNotes : undefined,
      pathways: plan.pathways?.length ? plan.pathways : override?.pathways,
      grcCourseListGuidance: plan.grcCourseListGuidance ?? override?.grcCourseListGuidance,
      sourceType: "detailed",
    });
  }

  return materializePlanReferenceCourses({
    ...plan,
    family: masterRow.family,
    bankIds: getMergedReferenceIds(plan.bankIds, masterRow.bankIds),
    chainIds: getMergedReferenceIds(plan.chainIds, masterRow.chainIds),
    plannerNote: plan.plannerNote ?? masterRow.note,
    officialLinks: uniquePlannerLinks([
      ...(plan.officialLinks ?? []),
      ...(override?.officialLinks ?? []),
    ]),
    degreeMapSections:
      plan.degreeMapSections?.length ? plan.degreeMapSections : override?.degreeMapSections,
    manualReviewNotes: mergedManualReviewNotes.length ? mergedManualReviewNotes : undefined,
    pathways: plan.pathways?.length ? plan.pathways : override?.pathways,
    grcCourseListGuidance: plan.grcCourseListGuidance ?? override?.grcCourseListGuidance,
    sourceType: "detailed",
  });
}

function inferGeneratedTrackId(row: TransferPlannerMasterMajorRow) {
  const searchableText = `${row.title} ${row.family} ${row.note}`.toLowerCase();
  const bankIds = new Set(row.bankIds);

  if (
    /bioengineering|chemical engineering|chemistry|biochemistry|biology|neuroscience/.test(
      searchableText
    ) ||
    (bankIds.has("BIO") && bankIds.has("CHEM"))
  ) {
    return "999O";
  }

  if (
    /computer|electrical|software|informatics|cyber|data science|quantitative|mathematical/.test(
      searchableText
    ) ||
    (bankIds.has("CS") && bankIds.has("ENGR"))
  ) {
    return "999P";
  }

  if (
    /mechanical|civil|aeronaut|industrial|materials|environmental engineering|construction/.test(
      searchableText
    ) ||
    (bankIds.has("ENGR") && bankIds.has("PHYS") && bankIds.has("CHEM"))
  ) {
    return "999Q";
  }

  if (bankIds.has("MATH") || bankIds.has("CS") || bankIds.has("PHYS")) {
    return "999B";
  }

  return null;
}

function buildGeneratedTrackSummary(trackId: string | null) {
  const track = trackId
    ? TRANSFER_PLANNER_TRACKS.find((entry) => entry.id === trackId) ?? null
    : null;

  if (!track) {
    return "Use the Green River class list and prerequisite/full-credit notes below to build a custom transfer path for this degree.";
  }

  return `${track.code} is the closest Green River base path for this degree. Use it as the backbone, then apply the major-specific Green River class list and chain notes below.`;
}

function buildGeneratedMajorPlan(row: TransferPlannerMasterMajorRow): TransferPlannerMajorPlan {
  const bestTrackId = inferGeneratedTrackId(row);
  const shortTitle = buildShortPlannerTitle(row.title);
  const campus = TRANSFER_PLANNER_CAMPUSES.find((entry) => entry.id === row.campusId);
  const override = GENERATED_PLAN_DOC_OVERRIDES[buildPlannerLookupKey(row.campusId, row.title)];

  return materializePlanReferenceCourses({
    id: buildPlannerPlanId(row.campusId, row.title),
    campusId: row.campusId,
    title: row.title,
    shortTitle: shortTitle || row.title,
    coverage: "partial",
    summary: `Current Green River -> UW planning reference for ${row.title}. Use the attached Green River class list and prerequisite/full-credit notes below as the baseline before final advisor review.`,
    applicationWindow: "Check the official program transfer page",
    startQuarter: "Varies by major",
    bestTrackId,
    bestTrackSummary: buildGeneratedTrackSummary(bestTrackId),
    whyThisTrack: [
      "This is the closest current Green River transfer-associate backbone for the major's math, science, or programming mix.",
      "Use the class list and chain sections below to decide which Green River classes are the strongest fit for this specific degree.",
    ],
    financialAidNote:
      "Keep your Green River associate track, aid load, and extra prerequisite classes aligned with advisor and financial-aid rules before adding elective bank courses.",
    applicationChecklist: [],
    beforeEnrollmentChecklist: [],
    stayAtGrcChecklist: [],
    advisorFlags: [
      "This planner row comes from the current master equivalency coverage and still needs program-by-program advisor confirmation for final admission strategy.",
    ],
    involvementIdeas: [],
    projectIdeas: [],
    officialLinks: campus?.officialLinks ?? [],
    manualReviewNotes: row.note ? [row.note] : undefined,
    family: row.family,
    bankIds: row.bankIds,
    chainIds: row.chainIds,
    plannerNote: row.note,
    sourceType: "master-generated",
    ...(override ?? {}),
  });
}

export const TRANSFER_PLANNER_MAJOR_PLANS = TRANSFER_PLANNER_DETAILED_MAJOR_PLAN_DEFINITIONS.map(
  mergeDetailedPlanWithMaster
);

const DETAILED_PLAN_LOOKUP_KEYS = new Set(
  TRANSFER_PLANNER_MAJOR_PLANS.map((plan) => {
    const masterRow = getMasterRowForPlan(plan);
    return buildPlannerLookupKey(plan.campusId, masterRow?.title ?? plan.title);
  })
);

export const TRANSFER_PLANNER_ALL_MAJOR_PLANS: TransferPlannerMajorPlan[] = [
  ...TRANSFER_PLANNER_MAJOR_PLANS,
  ...TRANSFER_PLANNER_MASTER_MAJOR_ROWS
    .filter(
      (row) => !DETAILED_PLAN_LOOKUP_KEYS.has(buildPlannerLookupKey(row.campusId, row.title))
    )
    .map(buildGeneratedMajorPlan),
].sort((left, right) => {
  const campusDelta =
    TRANSFER_PLANNER_CAMPUS_SORT_ORDER[left.campusId] -
    TRANSFER_PLANNER_CAMPUS_SORT_ORDER[right.campusId];

  if (campusDelta !== 0) return campusDelta;
  return left.title.localeCompare(right.title);
});

export function getTransferPlannerTrack(trackId: string | null) {
  if (!trackId) return null;
  return TRANSFER_PLANNER_TRACKS.find((track) => track.id === trackId) ?? null;
}

export function getTransferPlannerGrcCourseList(
  plan: TransferPlannerMajorPlan | null | undefined
) {
  if (!plan) return [] as string[];

  return uniqueReferenceCourseLabels(
    plan.grcCourseList ?? [
      ...getChecklistReferenceCourses(plan),
      ...getBankReferenceCourses(plan.bankIds),
    ]
  );
}

function formatAvailabilitySourceWindow(
  availability: Pick<TransferPlannerGrcCourseAvailabilityEntry, "years">
) {
  const labels = availability.years.map((year) => year.label).filter(Boolean);
  if (!labels.length) return "the latest published Green River annual schedules";
  if (labels.length === 1) return `the latest published ${labels[0]} Green River annual schedule`;
  if (labels.length === 2) {
    return `the latest published ${labels[0]} and ${labels[1]} Green River annual schedules`;
  }
  return `the latest published Green River annual schedules (${labels.join(", ")})`;
}

function formatAvailabilityStatusSummary(
  availability: Pick<
    TransferPlannerGrcCourseAvailabilityEntry,
    "status" | "years" | "latestPublishedQuarters"
  >
) {
  const yearSummaries = availability.years
    .filter((year) => year.quarters.length > 0)
    .map((year) => `${year.label}: ${formatAvailabilityQuarterList(year.quarters)}`);
  const sourceWindow = formatAvailabilitySourceWindow(availability);
  const latestPublishedYearLabel = availability.years[availability.years.length - 1]?.label ?? null;

  if (availability.status === "published-in-latest-schedule") {
    return yearSummaries.length
      ? `Recent GRC annual schedule history: ${yearSummaries.join("; ")}.`
      : null;
  }

  if (availability.status === "published-in-recent-history-not-latest") {
    if (yearSummaries.length) {
      const latestSuffix = latestPublishedYearLabel
        ? ` Not published in the latest ${latestPublishedYearLabel} annual schedule.`
        : ` Not published in ${sourceWindow}.`;
      return `Recent GRC annual schedule history: ${yearSummaries.join("; ")}.${latestSuffix}`;
    }
    return `Found in recent Green River annual schedule history, but not in ${sourceWindow}.`;
  }

  if (availability.status === "catalog-listed-not-in-latest-schedules") {
    return `Listed in the current Green River catalog, but not found in ${sourceWindow}.`;
  }

  if (availability.status === "legacy-track-only-no-current-public-source") {
    return `Referenced only by legacy Green River track history and not found in the current Green River catalog or ${sourceWindow}.`;
  }

  return `Still referenced by the planner, but not found in the current Green River catalog or ${sourceWindow}.`;
}

export function getTransferPlannerGrcCourseListGuidance(
  plan: TransferPlannerMajorPlan | null | undefined
) {
  const guidance = String(plan?.grcCourseListGuidance ?? "").trim();
  return guidance || null;
}

export function getTransferPlannerGrcCourseAvailability(
  courseLabel: string | null | undefined
): TransferPlannerCourseAvailability | null {
  const availabilityMap = TRANSFER_PLANNER_GRC_COURSE_AVAILABILITY as Record<
    string,
    TransferPlannerGrcCourseAvailabilityEntry
  >;

  for (const code of extractReferenceCourseCodes(String(courseLabel ?? ""))) {
    const entry = availabilityMap[code];
    if (!entry) continue;

    return {
      courseCode: code,
      status: entry.status,
      years: entry.years.map((year: TransferPlannerGrcCourseAvailabilityEntry["years"][number]) => ({
        label: year.label,
        quarters: [...year.quarters],
      })),
      latestPublishedQuarters: [...entry.latestPublishedQuarters],
    };
  }

  return null;
}

export function getTransferPlannerGrcCourseLatestPublishedQuarters(
  courseLabel: string | null | undefined
) {
  return getTransferPlannerGrcCourseAvailability(courseLabel)?.latestPublishedQuarters ?? null;
}

export function getTransferPlannerGrcCourseAvailabilitySummary(
  courseLabel: string | null | undefined
) {
  const availability = getTransferPlannerGrcCourseAvailability(courseLabel);
  if (!availability) return null;
  return formatAvailabilityStatusSummary(availability);
}

export function getTransferPlannerMajorsForCampus(campusId: TransferPlannerCampusId) {
  return TRANSFER_PLANNER_ALL_MAJOR_PLANS.filter((plan) => plan.campusId === campusId);
}

export function getTransferPlannerBankLabel(bankId: string) {
  return TRANSFER_PLANNER_BANK_LABELS[bankId] ?? bankId;
}

export function getTransferPlannerChainLabel(chainId: string) {
  return TRANSFER_PLANNER_CHAIN_LABELS[chainId] ?? chainId;
}

export function getTransferPlannerBanksForPlan(
  plan: TransferPlannerMajorPlan | null | undefined
) {
  if (!plan?.bankIds?.length) return [] as TransferPlannerReferenceBank[];

  return plan.bankIds
    .map((bankId) => MASTER_BANK_BY_ID.get(bankId) ?? null)
    .filter((bank): bank is TransferPlannerReferenceBank => !!bank);
}

export function getTransferPlannerChainsForPlan(
  plan: TransferPlannerMajorPlan | null | undefined
) {
  if (!plan?.chainIds?.length) return [] as TransferPlannerReferenceChain[];

  return plan.chainIds
    .map((chainId) => MASTER_CHAIN_BY_ID.get(chainId) ?? null)
    .filter((chain): chain is TransferPlannerReferenceChain => !!chain);
}
